// n8n Gmail node returns: From, To, Cc, Bcc, Subject (capitalized)
// Date as internalDate (ms timestamp), labels as array of {id, name}
var items = $input.all();
var results = [];

for (var i = 0; i < items.length; i++) {
  var e = items[i].json;

  // Date from internalDate (millisecond timestamp)
  var dateRaw = e.internalDate || e.date || e.Date || '';
  var dateStr = '';
  if (dateRaw) {
    try {
      var ts = Number(dateRaw);
      var d = ts > 1000000000000 ? new Date(ts) : (ts > 0 ? new Date(ts * 1000) : new Date(dateRaw));
      dateStr = d.toLocaleString('en-US', { timeZone: 'America/New_York', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', hour12: true });
    } catch(err) {
      dateStr = String(dateRaw).substring(0, 30);
    }
  }

  // From - capitalized field name
  var fromRaw = e.From || e.from || '';
  var fromName = '';
  var fromEmail = '';
  var angleMatch = String(fromRaw).match(/^(.+?)\s*<([^>]+)>/);
  if (angleMatch) {
    fromName = angleMatch[1].trim().replace(/^"|"$/g, '');
    fromEmail = angleMatch[2].trim().toLowerCase();
  } else {
    fromEmail = String(fromRaw).replace(/[<>]/g, '').trim().toLowerCase();
  }

  // Body
  var body = e.textPlain || e.text || e.snippet || e.body || '';
  var bodyPreview = String(body).substring(0, 200).replace(/\n/g, ' ');
  var fullBody = String(body).substring(0, 40000);

  // Attachments
  var attachments = [];
  var payload = e.payload || {};
  var parts = payload.parts || [];
  for (var p = 0; p < parts.length; p++) {
    var part = parts[p];
    if (part.filename && part.filename.length > 0) {
      attachments.push(part.filename);
    }
    var subParts = part.parts || [];
    for (var sp = 0; sp < subParts.length; sp++) {
      if (subParts[sp].filename && subParts[sp].filename.length > 0) {
        attachments.push(subParts[sp].filename);
      }
    }
  }

  // Labels - array of objects with .name
  var labels = e.labels || e.labelIds || [];
  var labelStr = '';
  if (labels.length > 0) {
    if (typeof labels[0] === 'object') {
      labelStr = labels.map(function(l) { return l.name || l.id || ''; }).join(', ');
    } else {
      labelStr = labels.join(', ');
    }
  }

  results.push({
    json: {
      'Message ID': e.id || e.messageId || 'no-id-' + i,
      'Thread ID': e.threadId || '',
      'Date': dateStr,
      'From Name': fromName,
      'From Email': fromEmail,
      'To': e.To || e.to || '',
      'CC': e.Cc || e.cc || e.CC || '',
      'BCC': e.Bcc || e.bcc || e.BCC || '',
      'Subject': e.Subject || e.subject || '',
      'Body Preview': bodyPreview,
      'Full Body': fullBody,
      'Attachment Names': attachments.join(', '),
      'Attachment Count': attachments.length,
      'Labels': labelStr
    }
  });
}

results.sort(function(a, b) {
  var dA = new Date(a.json['Date'] || 0).getTime();
  var dB = new Date(b.json['Date'] || 0).getTime();
  return dA - dB;
});

return results;

// n8n Gmail node returns: From, To, Cc, Bcc, Subject (capitalized)
// Date as internalDate (ms timestamp)
var items = $input.all();
var myEmail = 'abrownstein@3cventures.com';
var contactMap = {};

function parseEmailHeader(headerStr) {
  if (!headerStr) return [];
  var results = [];
  var parts = String(headerStr).split(/,(?=(?:[^<]*<[^>]*>)*[^>]*$)/);
  for (var i = 0; i < parts.length; i++) {
    var part = parts[i].trim();
    if (!part) continue;
    var angleMatch = part.match(/^(.+?)\s*<([^>]+)>/);
    if (angleMatch) {
      results.push({ name: angleMatch[1].trim().replace(/^"|"$/g, ''), email: angleMatch[2].trim().toLowerCase() });
    } else {
      var emailOnly = part.replace(/[<>]/g, '').trim().toLowerCase();
      if (emailOnly.includes('@')) {
        results.push({ name: '', email: emailOnly });
      }
    }
  }
  return results;
}

function addContact(email, name, relationship, subj, dt) {
  if (!email || email === myEmail) return;
  if (/noreply|no-reply|mailer-daemon|notifications?@|calendar-notification|postmaster/i.test(email)) return;
  if (!contactMap[email]) {
    contactMap[email] = { email: email, name: name || '', relationships: {}, subjects: [], dates: [], count: 0 };
  }
  var c = contactMap[email];
  if (name && (!c.name || c.name.length < name.length)) { c.name = name; }
  c.relationships[relationship] = true;
  if (subj) { c.subjects.push(dt + ': ' + subj); }
  if (dt) { c.dates.push(new Date(dt || 0).getTime()); }
  c.count = c.count + 1;
}

for (var idx = 0; idx < items.length; idx++) {
  var e = items[idx].json;
  // Capitalized field names from n8n Gmail node
  var fromStr = e.From || e.from || '';
  var toStr = e.To || e.to || '';
  var ccStr = e.Cc || e.cc || e.CC || '';
  var bccStr = e.Bcc || e.bcc || e.BCC || '';
  var subject = e.Subject || e.subject || '';

  // Date from internalDate (ms timestamp)
  var dateRaw = e.internalDate || e.date || e.Date || '';
  var dateStr = '';
  if (dateRaw) {
    try {
      var ts = Number(dateRaw);
      var d = ts > 1000000000000 ? new Date(ts) : (ts > 0 ? new Date(ts * 1000) : new Date(dateRaw));
      dateStr = d.toLocaleDateString('en-US', { timeZone: 'America/New_York' });
    } catch(err) {
      dateStr = String(dateRaw).substring(0, 10);
    }
  }

  var fromParsed = parseEmailHeader(fromStr);
  var toParsed = parseEmailHeader(toStr);
  var ccParsed = parseEmailHeader(ccStr);
  var bccParsed = parseEmailHeader(bccStr);

  var isSentByMe = false;
  for (var f = 0; f < fromParsed.length; f++) {
    if (fromParsed[f].email === myEmail) { isSentByMe = true; break; }
  }

  if (isSentByMe) {
    for (var t = 0; t < toParsed.length; t++) { addContact(toParsed[t].email, toParsed[t].name, 'Sent To', subject, dateStr); }
    for (var c1 = 0; c1 < ccParsed.length; c1++) { addContact(ccParsed[c1].email, ccParsed[c1].name, 'Sent To (CC)', subject, dateStr); }
    for (var b1 = 0; b1 < bccParsed.length; b1++) { addContact(bccParsed[b1].email, bccParsed[b1].name, 'Sent To (BCC)', subject, dateStr); }
  } else {
    for (var f2 = 0; f2 < fromParsed.length; f2++) { addContact(fromParsed[f2].email, fromParsed[f2].name, 'Received From', subject, dateStr); }
    for (var t2 = 0; t2 < toParsed.length; t2++) {
      if (toParsed[t2].email !== myEmail) { addContact(toParsed[t2].email, toParsed[t2].name, 'Co-Recipient (To)', subject, dateStr); }
    }
    for (var c2 = 0; c2 < ccParsed.length; c2++) {
      if (ccParsed[c2].email !== myEmail) { addContact(ccParsed[c2].email, ccParsed[c2].name, 'Co-Recipient (CC)', subject, dateStr); }
    }
  }
}

var keys = Object.keys(contactMap);
var results = [];
for (var k = 0; k < keys.length; k++) {
  var contact = contactMap[keys[k]];
  var relTypes = Object.keys(contact.relationships).sort().join(', ');
  var fullName = contact.name || '';
  var firstName = '';
  var lastName = '';
  if (fullName) {
    var nameParts = fullName.split(/\s+/);
    firstName = nameParts[0] || '';
    lastName = nameParts.slice(1).join(' ') || '';
  }
  var domain = contact.email.split('@')[1] || '';
  var company = domain.split('.')[0] || '';
  company = company.charAt(0).toUpperCase() + company.slice(1);
  var validDates = contact.dates.filter(function(d) { return d > 0; });
  var firstDate = '';
  var lastDate = '';
  if (validDates.length > 0) {
    validDates.sort(function(a, b) { return a - b; });
    firstDate = new Date(validDates[0]).toLocaleDateString('en-US', { timeZone: 'America/New_York' });
    lastDate = new Date(validDates[validDates.length - 1]).toLocaleDateString('en-US', { timeZone: 'America/New_York' });
  }
  var uniqueSubjects = [];
  var seen = {};
  for (var s = contact.subjects.length - 1; s >= 0 && uniqueSubjects.length < 20; s--) {
    if (!seen[contact.subjects[s]]) { seen[contact.subjects[s]] = true; uniqueSubjects.unshift(contact.subjects[s]); }
  }
  results.push({
    json: {
      'Email Address': contact.email,
      'Full Name': fullName,
      'First Name': firstName,
      'Last Name': lastName,
      'Company': company,
      'Relationship': relTypes,
      'Email Count': contact.count,
      'First Interaction': firstDate,
      'Last Interaction': lastDate,
      'Subjects & Dates': uniqueSubjects.join(' | '),
      'LinkedIn Connected': ''
    }
  });
}
results.sort(function(a, b) { return b.json['Email Count'] - a.json['Email Count']; });
return results;
